mapper.select:
SELECT COUNT(*)
FROM blacklist_report_comment
WHERE blacklist_report_seq = #{blacklistReportSeq}
  AND writer_member_seq = #{memberSeq}
  AND show_yn = 'Y'

SELECT vote_type
FROM blacklist_report_comment_vote
WHERE blacklist_report_comment_seq = #{blacklistReportCommentSeq}
  AND member_seq = #{memberSeq}

mapper.update:
UPDATE blacklist_report_comment_vote
   SET vote_type = #{voteType}
 WHERE blacklist_report_comment_seq = #{blacklistReportCommentSeq}
   AND member_seq = #{memberSeq}

UPDATE blacklist_report_comment
   SET like_count = IFNULL(like_count, 0) + #{deltaLike},
       dislike_count = IFNULL(dislike_count, 0) + #{deltaDislike}
 WHERE blacklist_report_comment_seq = #{blacklistReportCommentSeq}

UPDATE blacklist_report_comment
   SET report_count = IFNULL(report_count, 0) + 1
 WHERE blacklist_report_comment_seq = #{blacklistReportCommentSeq}

UPDATE blacklist_report_comment
   SET content = #{body.content},
       emoticon_seq_1 = #{body.emoticonSeq1},
       emoticon_seq_2 = #{body.emoticonSeq2},
       emoticon_seq_3 = #{body.emoticonSeq3},
       modify_dt = NOW()
 WHERE blacklist_report_comment_seq = #{blacklistReportCommentSeq}
   AND blacklist_report_seq = #{blacklistReportSeq}
   AND writer_member_seq = #{writerMemberSeq}
   AND show_yn = 'Y'

UPDATE blacklist_report_comment
   SET show_yn = 'N'
 WHERE blacklist_report_seq = #{blacklistReportSeq}
   AND show_yn = 'Y'
   AND (blacklist_report_comment_seq = #{rootCommentSeq}
        OR parent_blacklist_report_comment_seq = #{rootCommentSeq})

UPDATE blacklist_report_comment
   SET show_yn = 'N'
 WHERE blacklist_report_seq = #{blacklistReportSeq}
   AND blacklist_report_comment_seq = #{blacklistReportCommentSeq}
   AND show_yn = 'Y'

